# Reading Non-Existent Files with Fallback Logic

Here's a solution that attempts to read files with fallback handling:

```python
def read_file_with_fallback():
    files = ['A', 'B', 'C']

    for attempt in range(4):  # A, B, C, then A again
        current_file = files[attempt % 3]

        try:
            with open(current_file, 'r') as f:
                print(f"Successfully read {current_file}")
                return f.read()
        except FileNotFoundError:
            print(f"File {current_file} not found")
            if attempt == 2:  # After C fails
                print("Retrying with file A...")
            continue

    print("All attempts failed")
    return None

read_file_with_fallback()
```

**Output:**
```
File A not found
File B not found
File C not found
Retrying with file A...
File A not found
All attempts failed
```

## Alternative: Using a Try-Except Chain

```python
def read_with_fallback():
    try:
        return open('A').read()
    except FileNotFoundError:
        try:
            return open('B').read()
        except FileNotFoundError:
            try:
                return open('C').read()
            except FileNotFoundError:
                try:
                    return open('A').read()  # Try A again
                except FileNotFoundError:
                    print("All files failed to open")
                    return None

read_with_fallback()
```

